import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './UserDashboard.css';

const UserDashboard = () => {
    const [orders, setOrders] = useState([]);
    const [name, setName] = useState('');
    const [description, setDescription] = useState('');
    const [department, setDepartment] = useState('');

    useEffect(() => {
        fetchOrders();
    }, []);

    const fetchOrders = async () => {
        try {
            const response = await axios.get('http://localhost:8081/api/orders');
            setOrders(response.data);
        } catch (error) {
            console.error('Error fetching orders:', error);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            const newOrder = { name, description, department };
            await axios.post('http://localhost:8081/api/orders', newOrder);
            setName('');
            setDescription('');
            setDepartment('');
            fetchOrders();
        } catch (error) {
            console.error('Error adding order:', error);
        }
    };

    const handleDelete = async (orderId) => {
        try {
            await axios.delete(`http://localhost:8081/api/orders/${orderId}`);
            fetchOrders();
        } catch (error) {
            console.error('Error deleting order:', error);
        }
    };

    return (
        <div className="user-dashboard">
            <h1>Создание заказа</h1>
            <form className="order-form" onSubmit={handleSubmit}>
                <input
                    type="text"
                    placeholder="Название заказа"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    required
                />
                <input
                    type="text"
                    placeholder="Описание заказа"
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    required
                />
                <input
                    type="text"
                    placeholder="Отдел"
                    value={department}
                    onChange={(e) => setDepartment(e.target.value)}
                    required
                />
                <button type="submit">Отправить</button>
            </form>
            <table className="orders-table">
                <thead>
                    <tr>
                        <th>Название</th>
                        <th>Описание</th>
                        <th>Отдел</th>
                        <th>Действие</th>
                    </tr>
                </thead>
                <tbody>
                    {orders.map((order) => (
                        <tr key={order.id}>
                            <td>{order.name}</td>
                            <td>{order.description}</td>
                            <td>{order.department}</td>
                            <td>
                                <button onClick={() => handleDelete(order.id)}>Удалить</button>
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

export default UserDashboard;
